from __future__ import annotations

import json
from dataclasses import dataclass
from pathlib import Path
from typing import Literal


@dataclass
class RequestSample:
    id: str
    messages: list[dict[str, str]]
    model: str
    max_tokens: int
    temperature: float
    seed: int
    # M5.2 (FR-005c chat-corpus): auto-derived from prompt length when the
    # corpus is generated by ``scripts/python/gen_chat_corpus.py``. The
    # harness records the bucket on each per-request sidecar event so
    # post-hoc analysis can stratify TTFT by prompt-length bucket
    # (short/medium/long). Optional with default "unspecified" so
    # pre-M5.2 corpora (chat_nonstreaming.json without the field) load
    # unchanged.
    bucket: str = "unspecified"


@dataclass
class CompletionTextSample:
    id: int | str
    prompt: str
    model: str
    max_tokens: int
    seed: int
    bucket: str = "short"


@dataclass
class CompletionEmbedSample:
    id: int
    tensor_bytes: bytes
    max_tokens: int
    seed: int
    seq_len: int
    bucket: str


def load_completions_corpus(
    corpus_type: Literal["text", "embeds"],
    corpus_dir: Path | None = None,
) -> list[CompletionTextSample] | list[CompletionEmbedSample]:
    if corpus_dir is None:
        corpus_dir = Path(__file__).parent.parent.parent / "corpus"

    if corpus_type == "text":
        path = corpus_dir / "completions_text.json"
        if not path.exists():
            raise FileNotFoundError(
                f"Completions text corpus not found: {path}. "
                "Create tools/benchmark/corpus/completions_text.json first."
            )
        raw = json.loads(path.read_text())
        return [
            CompletionTextSample(
                id=item["id"],
                prompt=item["prompt"],
                model=item["model"],
                max_tokens=item["max_tokens"],
                seed=item["seed"],
                bucket=item.get("bucket", "short"),
            )
            for item in raw
        ]

    # corpus_type == "embeds"
    manifest_path = corpus_dir / "completions_embeds" / "manifest.json"
    if not manifest_path.exists():
        raise FileNotFoundError(
            f"Completions embeds manifest not found: {manifest_path}. "
            "Run scripts/python/gen_embed_corpus.py first."
        )
    try:
        import io

        import torch
    except ImportError as exc:
        raise ImportError(
            "torch is required to load embedding corpus. Install it with: uv sync --all-packages"
        ) from exc

    manifest = json.loads(manifest_path.read_text())
    samples: list[CompletionEmbedSample] = []
    for entry in manifest:
        pt_path = corpus_dir.parent / entry["embed_file"]
        if not pt_path.exists():
            raise FileNotFoundError(
                f"Embedding file not found: {pt_path}. "
                "Run scripts/python/gen_embed_corpus.py first."
            )
        tensor: object = torch.load(str(pt_path), weights_only=True)
        buf = io.BytesIO()
        torch.save(tensor, buf)
        samples.append(
            CompletionEmbedSample(
                id=entry["id"],
                tensor_bytes=buf.getvalue(),
                max_tokens=entry["max_tokens"],
                seed=entry["seed"],
                seq_len=entry["seq_len"],
                bucket=entry["bucket"],
            )
        )
    return samples


def load_corpus(path: Path) -> list[RequestSample]:
    raw = json.loads(path.read_text())
    if not raw:
        raise ValueError(f"Corpus at {path} is empty")
    return [
        RequestSample(
            id=item["id"],
            messages=item["messages"],
            model=item["model"],
            max_tokens=item["max_tokens"],
            temperature=item["temperature"],
            seed=item["seed"],
            bucket=item.get("bucket", "unspecified"),
        )
        for item in raw
    ]


# M5.2 default chat corpus path. Used by the M5.2 sweep when no
# ``--m5_2-corpus`` flag is passed. The companion ``.provenance.json``
# file records the ShareGPT source revision SHA + filter criteria so the
# audit trail is reproducible.
DEFAULT_CHAT_CORPUS_PATH = (
    Path(__file__).resolve().parent.parent.parent / "corpus" / "chat_sharegpt_1000.json"
)
